INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1810_L036$$, 2026, $$The Combat Autonomous Maritime Platform (CAMP) Extra Large Unmanned Undersea Vehicle (XLUUV) is a Navy's Extra Large UUV effort as part of the Family of UUVs. CAMP XLUUV is a multi-phased
 accelerated acquisition effort to rapidly deliver capability to the Fleet. CAMP XLUUV's will have a modular payload bay, with defined interfaces that will support current and future payloads. The XLUUV effort
 will include support of future systems and integration of current and future payloads. Providing the Navy with unprecedented optionality for scalable payloads and sensor suites tailored for missions ranging from
 surveillance to strike. Liberator is a stationary undersea system positioned on the seabed for operationally relevant durations to provide payloads in designated areas to partially address capability gaps.

 The FY 2026 spend plan for Extra Large Unmanned Undersea Vehicle includes $0 thousand of discretionary and $3,313 thousand of mandatory (reconciliation) for a total of $3,313 thousand. The mandatory
 funds support equipment costs and readiness for XLUUV.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Navy                                                                                                                    Date: April 2026
