INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1810_L068$$, 2026, $$Network Tactical Common Data Link (NTCDL) provides the ability to transmit/receive real-time intelligence, surveillance, and reconnaissance (ISR) data simultaneously from multiple sources (air, surface, sub-
 surface, and manportable) and exchange command and control information (voice, data, imagery, and full-motion video) across dissimilar joint, service, coalition, and civil networks. NTCDL provides warfighters
 the capability to support multiple, simultaneous, networked operations with in-service Common Data Link (CDL) equipped aircraft (e.g., MH- 60R) in addition to next-generation manned and unmanned platforms.
 NTCDL benefits the Fleet by providing a horizon extension for line-of-sight systems for use in time-critical strike missions.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Navy                                                                                                                      Date: April 2026
